var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"로터스, 아마니 밸리. 코핀 컴퍼니 임시 지부 인근 착륙장.","JPN":"ロータス、アマニーバレー。コフィンカンパニーの臨時支部付近の着陸場。","ENG":"Lotus, Amani Valley. Landing strip near the temporary Coffin Company Branch.","TWN":"洛德斯，和平谷。科芬臨時分公司附近的停機坪。"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_UI_RECRUITMNET_HELICOPTER_START"},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"몸은 좀 괜찮아졌나?","JPN":"体の調子はどうだ？","ENG":"Feeling any better?","TWN":"身體好點了嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"보다시피.","JPN":"見てのとおりだ。","ENG":"As you can see.","TWN":"正如你所見。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"피를 잔뜩 흘렸더니 오히려 홀가분해진 것 같기도 해.","JPN":"血をたくさん流したら、すっきりした気すらする。","ENG":"I do feel a bit relieved after losing a lot of blood.","TWN":"流了很多血，反而覺得輕鬆了些。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"여태까지 난, 내가 피도 눈물도 없는 놈이 된 줄 알았는데 말이야.","JPN":"今まで私は、自分が血も涙もないやつだと思っていたのにな。","ENG":"I always thought that I was heartless.","TWN":"直到之前，我還以為自己是個沒血沒淚的人呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"넌 성공에 필요하다면 자신이라도 걸겠다고 했었지.","JPN":"お前は成功のためなら自分自身も賭けると言ったな。","ENG":"You did say that you would risk your life if it meant pulling this off.","TWN":"你曾說過，為了成功你甚至願意賭上自己。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 말이 의미 그대로일 줄은 몰랐군.","JPN":"まさか言葉どおりの意味だったとは思わなかった。","ENG":"But I didn't think you meant it literally.","TWN":"我沒想到那句話會是字面的意思。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"고작 권총 하나로 뭘 하겠다고 잘난 듯이 사도를 가로막았던 거냐?","JPN":"たかが拳銃1丁で使徒に立ち向かうとは……どうするつもりだったんだ？","ENG":"Who in their right mind would confront an Apostle with just a pistol?","TWN":"你以為憑一把手槍就能擋住使徒嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"난 선택한 것 뿐일세.","JPN":"私は選択しただけさ。","ENG":"I just made a choice.","TWN":"只是我的選擇而已。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"앞으로의 마왕들… 그리고 탐미엘에게 대적하기 위해 가장 필요한 건, 내 잔꾀가 아니라 자네의 힘일 테니 말이야.","JPN":"これから魔王たち……そしてタミエルに立ち向かうために最も必要なのは、私の浅知恵ではない、君の力だからね。","ENG":"Because what we need most to fight against Tammiel and the Demon Lords that will soon come... is not my clever tricks, but your strength.","TWN":"今後要對抗魔王……還有塔米爾，最需要的不是我的小聰明，而是你的力量。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"난 질문을 한 게 아니다.","JPN":"別に質問をしたわけではない。","ENG":"It was a rhetorical question.","TWN":"我不是在問你問題。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다신 그런 멍청한 짓은 하지 말라는 뜻이지.","JPN":"2度とあんなバカなことはするなと言っているのだ。","ENG":"I meant to tell you to never do something that idiotic again.","TWN":"我的意思是今後不要再做那種蠢事了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…조심하겠네.","JPN":"……気をつけよう。","ENG":"...I'll be careful.","TWN":"……我會小心的。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"최고관리자, 깨어났다고 들었어.","JPN":"最高管理者、目が覚めたって聞いた。","ENG":"I heard you woke up, Supreme Administrator.","TWN":"最高管理者，聽說你醒了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"당신이 부탁한 <color=#ffd34c>전환기</color>의 프로토타입이 나와서 시험 가동을 해볼 건데. 참관할 거야?","JPN":"あなたに頼まれた<color=#ffd34c>転換器</color>のプロトタイプが完成して、テスト稼働をする予定だけど、見る？","ENG":"I was just about to test run the prototype of the <color=#ffd34c>converter</color> you requested. Care to join?","TWN":"你要求的<color=#ffd34c>變軌器</color>原型已經做出來了，我打算開始測試。你要來觀摩嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…아파서 못 오는 거면 어쩔 수 없고.","JPN":"……怪我のせいで来れないなら、別にいい。","ENG":"...Even if you can't, it's all good.","TWN":"……如果是因為生病不能來，那也沒辦法。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 문제없네. 지금 가도록 하지.","JPN":"いや、問題ない。今向かおう。","ENG":"No, I'm good. I'll be right there.","TWN":"不，沒有問題。我馬上就來。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"파블린의 아이는… 어떻게 할 셈이지?","JPN":"パブリンの子どもは……どうする？","ENG":"What are you going to do... with Pavlin's child?","TWN":"帕芙琳的孩子……你打算怎麼辦？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"글쎄. 우리가 겪어 나갈 풍파에 휘말리게 하고 싶진 않군.","JPN":"そうだな。これから私たちが飛び込む嵐に巻き込みたくはない。","ENG":"I'm not sure. But I don't want her to get caught in the storm we are about to undergo.","TWN":"嗯。我不想讓她捲入我們即將經歷的風暴之中。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리국에서 보호하는 것도 나쁘지 않다고 생각하지만… 가장 중요한 건 본인의 의사겠지.","JPN":"管理局で保護するのも悪くないとは思うが……何より大事なのは本人の意思だ。","ENG":"It wouldn't be a bad idea for the Administration to protect her, but... what's most important is what she wants.","TWN":"雖然我覺得讓管理局保護她也不錯……但最重要的還是本人的意願吧。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"식사 시간이에요, 여러분.","JPN":"皆さん、食事の時間です。","ENG":"It's mealtime, everyone.","TWN":"吃飯囉，大家。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"맛있는 음식, 그리고 꽃 한 송이씩 받아가세요.","JPN":"おいしい食べ物と、花を一輪ずつ受け取ってくださいね。","ENG":"Have some good food and get your flower too.","TWN":"請享用美食吧～還有，我為大家每個人都準備了一朵花～"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHILD_EXTRA_NULL_NULL","text":{"KOREA":"고맙습니다, 언니.","JPN":"ありがとう、お姉ちゃん。","ENG":"Thank you.","TWN":"謝謝你，姊姊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PATIENT_NPC_NULL_NULL","text":{"KOREA":"아이고, 고마워요. 귀여운 아가씨.","JPN":"ありがとう。かわいいお嬢さん。","ENG":"Oh, my. Thank you, little missy.","TWN":"哎呀，謝謝你。可愛的小朋友。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"PATIENT_NPC_NULL_NULL","text":{"KOREA":"이건 꽃집에서 키운 건가? 내 나중에 한 번 들를게요.","JPN":"これは花屋で育てたものかな？　今度お店に行きますね。","ENG":"Did you get them at a flower shop? I'll make sure to visit later.","TWN":"這是在花店買的嗎？我以後想去看看。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"아뇨. 방금 마당에서 피워낸 꽃이에요.","JPN":"いいえ、先程庭で咲かせた花です。","ENG":"No. These are flowers that bloomed in the yard just now.","TWN":"不，這是剛剛在院子裡開的花。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"PATIENT_NPC_NULL_NULL","text":{"KOREA":"병원 마당…? 거긴 십 년째 잡초 밖에 자라지 않을 텐데…","JPN":"病院の庭……？　あそこは10年間、雑草しか生えなかった場所のはず……","ENG":"The hospital's yard...? But there has been nothing but weeds growing there for decades.","TWN":"醫院的庭院……？那裡十年來只長雜草吧……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"CHILD_EXTRA_NULL_NULL","text":{"KOREA":"와아, 창밖 좀 봐요! 마당에 꽃들이 한가득 피어있어요!","JPN":"わあ、外を見て！　庭に花がたくさん咲いてますよ！","ENG":"Wow! Look out the window! The yard is full of flowers!","TWN":"哇，快看窗外！院子裡開滿了花耶！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PATIENT_NPC_NULL_NULL","text":{"KOREA":"…정말이잖아?","JPN":"……本当だ。","ENG":"...You're right...!","TWN":"……真的啊？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PATIENT_NPC_NULL_NULL","text":{"KOREA":"하룻밤 사이에 기적이라도 일어난 건가?","JPN":"昨日の夜、奇跡でも起きたのかな？","ENG":"Did a miracle happen overnight?","TWN":"難道是一夜之間發生了奇蹟嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"저 아이 어제부터 자주 보이던데, 누군지 아세요?","JPN":"あの子、昨日から見かけるようになったけど、誰ですか？","ENG":"I've been seeing her quite a lot since yesterday. Does anyone know who she is?","TWN":"那孩子從昨天開始就經常出現，你知道她是誰嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"관리국에서 입원 시킨 환자 분인데, 본인이 자원해서 배식을 돕고 있습니다.","JPN":"管理局で入院させた患者さんですが、本人の希望で配膳を手伝ってもらっています。","ENG":"She is a patient admitted by the Administration, and she volunteered to help distribute food.","TWN":"好像是管理局收容的患者，她幫忙分發餐點都是自願的。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"환자가 배식을요…?","JPN":"患者が配膳を……？","ENG":"A patient is helping with the food...?","TWN":"自願幫忙的嗎……？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"하하… 괜찮다고 했는데, 다른 환자 분들이 저렇게 좋아하니 말릴 필요는 없어 보여서요.","JPN":"はは……最初は断ったんですけど、他の患者さんたちが喜ぶから……止めなくてもいいかなと思って。","ENG":"Haha... We told her to rest, but I don't think we need to be concerned as the other patients don't seem to have any problems with it.","TWN":"哈哈……我們原本還想阻止她的，但其他患者也很喜歡她，看來沒必要阻止。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"맛있게 먹어요, 크리스.","JPN":"どうぞ、クリス。","ENG":"Enjoy your meal, Chris.","TWN":"要好好享用喔，克莉絲。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아… 감사합니다.","JPN":"あ……ありがとうございます。","ENG":"Oh... Thank you.","TWN":"啊……謝謝。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그리고 이건 선물이에요.","JPN":"あとこれはプレゼントです。","ENG":"And this is a gift.","TWN":"還有，這是禮物。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 그림이네요. 고맙습니다.","JPN":"あっ、絵ですね。ありがとうございます。","ENG":"Oh, it's a drawing. Thank you.","TWN":"啊，真是幅好畫。謝謝……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"뭘 표현한 거지? 갈색의 웅크리고 있는… 카피바라 추상화?","JPN":"何の絵だろう？　茶色い何かが……うずくまってる……カピバラの抽象画？","ENG":"What did you draw? Is it an abstract painting... of a brown, curled up capybara?","TWN":"這是畫的什麼……？棕色的蜷縮著的……水豚嗎……？好抽象啊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"크리스가 잠든 모습이 귀여워서 그림으로 남겨봤거든요.","JPN":"寝ているクリスがあまりにもかわいくて、絵にしてみたんです。","ENG":"I thought you looked cute sleeping, so I drew you.","TWN":"克莉絲睡著的樣子很可愛，所以我把她畫了下來。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"와아- 역시 저였군요. 한 눈에 알아봤어요.","JPN":"わあ～やっぱり私の似顔絵だったんですね。一目でわかりました。","ENG":"Wow... So it is me. I knew it the moment I saw it.","TWN":"哇～果然是我啊。一眼就認出來了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그나저나 솔로베도 환자인데, 이렇게 돌아다녀도 괜찮나요?","JPN":"それより、ソロベーも患者なのに歩き回っていいんですか？","ENG":"But Solovey, you're a patient here too. Is it okay for you to walk around like that?","TWN":"話說回來，蘇羅薇也是患者，這樣到處走動沒關係嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그럼요! 안정을 취하래서 시킨 대로 하는 중이에요.","JPN":"もちろんです！　絶対安静って言われたから、ちゃんと言われたとおりにしてます。","ENG":"Yup! They told me to take it easy, so I'm following their advice.","TWN":"當然了！醫生說要靜養，我就照做了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"아침마다 정원을 돌보곤 했는데, 아무것도 안 하려니 불안하더라고요.","JPN":"いつもは毎朝庭園の手入れをしてたのに、急に何もしなくなったら不安になってしまって。","ENG":"I used to tend the garden every morning, so doing nothing makes me feel anxious.","TWN":"以前我每天早上都會照料花園，現在什麼都不做，反而覺得不安。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하하… 그런 의미의 안정은 아닌 것 같지만…","JPN":"はは……安静ってそういう意味じゃないと思いますけど……","ENG":"Haha... I don't think that's what they meant...","TWN":"哈哈…… 你好像誤解他們的意思了……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그래도 건강해 보이니 다행이네요.","JPN":"でも元気そうでなによりです。","ENG":"But I'm glad you look well.","TWN":"不過你看起來氣色很好，真是太好了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"안녕하세요. 맛있는 밥 가져왔어요,","JPN":"こんにちは。おいしいごはんを持ってきました。","ENG":"Hello. I brought you some delicious food.","TWN":"你好。我帶來了美味的飯菜,"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_DOOR_SLIDE"},{"id":"L29_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아, 난 괜찮아.","JPN":"あ、私は大丈夫だよ。","ENG":"Oh, I'm good.","TWN":"啊，我沒事。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"오늘 퇴원하거든. 지금 막 떠나려던 참이고.","JPN":"今日退院するの。今出ようとしてたとこ。","ENG":"I get discharged today. And I was just on my way out.","TWN":"今天就要出院了，正準備離開。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어…….","JPN":"え……","ENG":"Uh...","TWN":"嗯……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"저기, 왜 그래? 내 얼굴에 뭐 묻었나?","JPN":"ん？　どうしたの？　私の顔に何かついてる？","ENG":"Hmm? What's wrong? Is there something on my face?","TWN":"那個，怎麼了？我的臉上沾到什麼了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"닮았어요. 어머니의 동료 분이랑.","JPN":"似てるんです。お母さんの仲間の方と……","ENG":"Mother's comrade... You look like her.","TWN":"好像喔，你和我媽媽的同事長得好像。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"네 어머니…?","JPN":"あなたのお母さん……？","ENG":"Your mother...?","TWN":"你媽媽……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"마침 모여 있었군.","JPN":"ちょうどここに集まっていたのか。","ENG":"Okay, everyone's here.","TWN":"很好，你們正好都在。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"논의할 얘기가 있는데, 두 사람 모두 시간 괜찮겠지?","JPN":"相談したいことがあるのだが、2人とも少しいいか？","ENG":"There are a few things to discuss, and you two have time, right?","TWN":"有些事情需要討論，你們兩個有時間的吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"나야 당연히 괜찮지만, 이 애도 같이?","JPN":"私はいいけど、この子も一緒なの？","ENG":"I don't mind, but her too?","TWN":"我當然沒問題，不過這個孩子也要一起嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"굳이 우리와 함께 하지 않더라도, 세상 돌아가는 일을 알아둬서 나쁠 건 없으니까.","JPN":"私たちと行動は共にせずとも、この世界について知っておいて損はないからな。","ENG":"Even if she won't be with us, there's no harm in her knowing what's going on in the world.","TWN":"即使不和我們一起去，了解一下世事也沒有壞處。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이수연이 스완의 행방을 찾았다.","JPN":"カナミ・キズナが、スワンの行方を突き止めた。","ENG":"Lee Sooyeon found Swan's whereabouts.","TWN":"李秀妍找到史旺的下落了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};